import{c as a,Q as t,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"The Rundown AI — 2026-04-17","description":"","frontmatter":{"title":"The Rundown AI — 2026-04-17","date":"2026-04-17T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-17-the-rundown-ai.md","filePath":"research/ai-news/2026-04/2026-04-17-the-rundown-ai.md","lastUpdated":1779898012000}'),i={name:"research/ai-news/2026-04/2026-04-17-the-rundown-ai.md"};function o(p,e,s,d,u,l){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="🗞️-the-rundown-ai-—-2026-04-17" tabindex="-1">🗞️ The Rundown AI — 2026-04-17 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-04-17" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-04-17&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="openai-s-superapp-hiding-inside-codex" tabindex="-1"><a href="https://www.therundown.ai/p/openai-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">OpenAI&#39;s superapp hiding inside Codex</a> <a class="header-anchor" href="#openai-s-superapp-hiding-inside-codex" aria-label="Permalink to &quot;[OpenAI&#39;s superapp hiding inside Codex](https://www.therundown.ai/p/openai-superapp-hiding-inside-codex)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-04-17</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Advertise</a></p><p><a href="https://lovable.link/VLdkdap?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer"></a></p><p>Good morning, AI enthusiasts. OpenAI has been teasing a superapp for months. Today, it shipped a major first piece.</p><p>With a major Codex update bringing new features like background computer use, an in-app browser, parallel agents, and more, the rollout is OpenAI&#39;s clearest step yet toward the all-in-one platform it&#39;s been building out in the open.</p><p>In today’s AI rundown:</p><p>OpenAI’s superapp shift with Codex update</p><p>Anthropic&#39;s Opus 4.7 tops rivals, trails Mythos</p><p>Run an LLM on your laptop for free with Ollama</p><p>OpenAI’s first science domain-specific model</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>OPENAI</p><p>🧰 <a href="https://openai.com/index/codex-for-almost-everything/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">OpenAI’s superapp shift with Codex update</a></p><p>Image source: OpenAI</p><p>The Rundown: OpenAI just <a href="https://openai.com/index/codex-for-almost-everything/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">updated</a> its Codex platform, shifting it from a coding agent to a cohesive ChatGPT + Atlas + Codex app with features like background computer use, parallel agents, an in-app browser, image generation, and more.</p><p>The details:</p><p>Background computer use lets Codex operate any Mac app on its own, with several agents also able to work at once, even in apps without APIs.</p><p>Memory (in preview) now retains preferences and context across sessions, while automations let Codex pick up long-running tasks days later.</p><p>An Atlas-powered in-app browser lets developers mark up pages to direct Codex, while inline gpt-image-1.5 creates mockups without switching apps.</p><p>Codex hit 3M weekly users with 70% month-over-month growth, and Codex head Thibault Sottiaux said OpenAI is &quot;building the super app out in the open.&quot;</p><p>Why it matters: Anthropic hit a home run with Claude Code and Cowork, and this is OpenAI’s biggest challenge to it yet — bringing Codex on a similar playing field with an expansion of capabilities far beyond just an agentic coding assistant. With the company building a ‘superapp’, this feels like a big first shift towards that vision.</p><p>TOGETHER WITH LOVABLE</p><p>🛠️ <a href="https://lovable.link/VLdkdap?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Your app idea doesn&#39;t need a dev team</a></p><p><a href="https://lovable.link/VLdkdap?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Hiring developers or learning to code used to be the only way to bring a product to life. Lovable removes that barrier entirely — its AI builds real, usable apps and websites from a simple text description.</p><p>Millions of users are already building with Lovable to:</p><p>Go from idea to a functional, customer-ready app in minutes, not months</p><p>Launch Shopify stores, admin tools, landing pages, and more with simple prompts</p><p>Launch real businesses, validate ideas, and save thousands in dev costs</p><p><a href="https://lovable.link/VLdkdap?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Start building for free at lovable.dev today</a>.</p><p>ANTHROPIC</p><p>⚙️ <a href="https://www.anthropic.com/news/claude-opus-4-7?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Anthropic&#39;s Opus 4.7 tops rivals, trails Mythos</a></p><p>Image source: Anthropic</p><p>The Rundown: Anthropic just <a href="https://www.anthropic.com/news/claude-opus-4-7?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">released</a> Claude Opus 4.7, the company’s new top publicly available model that tops GPT-5.4 and Gemini 3.1 Pro on agentic coding — though still lags behind the company&#39;s own unreleased Mythos Preview.</p><p>The details:</p><p>Opus 4.7 jumps from 4.6&#39;s 53.4% on SWE-bench Pro coding benchmark to 64.3%, with the gated Mythos Preview still ahead at 77.8%.</p><p>The model is priced identically to Opus 4.6 for API usage, though the upgrade uses tokens significantly faster than its predecessor.</p><p>Other rollouts include a Claude Code default ‘xhigh’ effort in between high and max, and an /ultrareview slash command that flags bugs and design issues.</p><p>The release comes amid user complaints of degraded performance on 4.6, with 4.7 early reactions also coming out divided on capabilities despite benchmarks.</p><p>Why it matters: Anthropic is now running two parallel tracks: a fast 2-month public release cadence and a gated frontier line in Mythos, accessible only to exclusive partners. That split lets the company stress-test its most powerful models, but also marks one of the first times public access feels behind the true frontier.</p><p>AI TRAINING</p><p>🦙 <a href="https://app.therundown.ai/guides/run-an-llm-on-your-laptop-for-free-with-ollama?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Run an LLM on your laptop for free with Ollama</a></p><p><a href="https://app.therundown.ai/guides/run-an-llm-on-your-laptop-for-free-with-ollama?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to install Ollama and run a real AI model on your laptop for free. No subscription, no account, and no data leaving your machine.</p><p>Step-by-step:</p><p>Go to <a href="https://ollama.com/download?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">ollama.com/download</a>, get the installer for your Mac / Linux / Windows PC, and set it up. Open the app once it&#39;s installed</p><p>In the app, go to New Chat, select a lightweight model like gemma3 (about 3GB, suitable for any 8GB RAM laptop), and wait for it to download</p><p>After the model downloads, type a prompt and hit enter. That&#39;s it. You&#39;re chatting with a real AI running entirely on your laptop</p><p>Try turning on airplane mode and sending another message to watch it work with no internet at all</p><p>Pro tip: You can use Ollama&#39;s API to give your model access to web and other tools. You can also point a coding agent like Claude Code at the model and run it for free.</p><p>PRESENTED BY FIDDLER</p><p>💸 <a href="https://www.fiddler.ai/guides/tco-for-operationalizing-agents?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=tco-guide" target="_blank" rel="noreferrer">Cut the trust tax of evaluating AI agents at scale</a></p><p><a href="https://www.fiddler.ai/guides/tco-for-operationalizing-agents?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=tco-guide" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Evaluating agents with external LLMs looks affordable. Until your agent traffic grows. Fiddler’s guide breaks down how to reduce Total Cost of Ownership while eliminating risk gaps in production.</p><p>Learn how to:</p><p>Evaluate every trace without sampling</p><p>Evaluate agents in-environment with batteries-included Trust Models</p><p>Reduce API costs at scale</p><p><a href="https://www.fiddler.ai/guides/tco-for-operationalizing-agents?utm_source=rundownai&amp;utm_medium=online_advertising&amp;utm_campaign=tco-guide" target="_blank" rel="noreferrer">Download the Agentic TCO Guide now</a>.</p><p>OPENAI</p><p>🧬 <a href="https://openai.com/index/introducing-gpt-rosalind/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">OpenAI’s first science domain-specific model</a></p><p>Image source: OpenAI</p><p>The Rundown: OpenAI <a href="https://openai.com/index/introducing-gpt-rosalind/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">launched</a> GPT-Rosalind, the first model in a new life sciences series built for drug discovery and biological research, and the company&#39;s first real step into domain-specialized reasoning — following Tuesday&#39;s GPT-5.4-Cyber.</p><p>The details:</p><p>Rosalind can read scientific papers, query lab databases, design experiments, and generate biological hypotheses, simplifying the research process.</p><p>The model shows strong jumps on science-specific benchmarks for biochemistry, experiment design, tool usage, and more over GPT-5.4.</p><p>On a blind RNA test from gene therapy lab Dyno Therapeutics, Rosalind&#39;s answers scored better than 95% of human scientists on prediction tasks.</p><p>The model is available to qualifying enterprise users during the test phase, with companies like Amgen, Moderna, and the Allen Institute already using it.</p><p>Why it matters: Tuesday, it was GPT-5.4-Cyber, and today, it&#39;s GPT-Rosalind. That&#39;s two domain models in three days, showing a trend — the flagship may be good at everything, but the actual massive wedges at the top of industries like defending networks or designing drugs may need purpose-built models.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🤖 <a href="http://www.rundown.ai/tools/claude-opus-4-7?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Claude Opus 4.7</a> - Anthropic’s new top AI with advanced agentic coding</p><p>⚙️ <a href="https://www.rundown.ai/tools/windsurf-2-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Windsurf 2.0</a> - Agentic IDE with new command center, Devin cloud agent</p><p>🚀 <a href="https://www.rundown.ai/tools/codex?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Codex</a> - OAI&#39;s coding agent, now with computer use, in-app browser, more</p><p>🧠 <a href="https://www.rundown.ai/tools/hy-world-2-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">HY-World 2.0</a> - Tencent’s world model that creates interactive 3D scenes</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>Perplexity <a href="https://www.perplexity.ai/hub/blog/personal-computer-is-here?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">rolled out</a> Personal Computer, a Max-tier Mac app that runs agents across 20+ frontier models to drive native apps, read files, and pilot its Comet browser 24/7.</p><p>Windsurf <a href="https://windsurf.com/blog/windsurf-2-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">launched</a> 2.0, adding an Agent Command Center with a new command center view for fleets of parallel cloud and local agents and bringing Devin into the IDE.</p><p>Tencent&#39;s Hunyuan team <a href="https://x.com/TencentHunyuan/status/2044604754836505076?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">open-sourced</a> HY-World 2.0, a world model that generates editable 3D scenes with physics-aware movement, pushing directly into 3D pipelines.</p><p>The U.S. government is reportedly <a href="https://www.bloomberg.com/news/articles/2026-04-16/white-house-moves-to-give-us-agencies-anthropic-mythos-access?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">preparing</a> to give certain agencies access to Anthropic’s Mythos AI, despite the blacklist and current legal battle with the company.</p><p>Alibaba’s ATH team <a href="https://x.com/AlibabaGroup/status/2044634595937882394?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">introduced</a> Happy Oyster in beta, a new world model that can create interactive 3D environments on the fly from multimodal inputs.</p><p>COMMUNITY</p><p>🤝 <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Jerry G. in Gig Harbor, WA:</p><p>&quot;I&#39;m a 73-year-old author and screenwriter. I have been using Claude to build my last two books. Claude helped design the book covers, formatted the interior, and even suggested titles for my stories.</p><p>Now that they are printed, Claude helps me market them to book clubs, libraries, and social media sites. Claude helped me build a Substack following and post bi-weekly new stories on Instagram and BlueSky. I&#39;m a Claude convert and won&#39;t write any more books with his assistance.”</p><p>How do you use AI? Tell us <a href="https://docs.google.com/forms/d/e/1FAIpQLSfH4UPzu72HTpdb08Qlm-0dLwKJIjdcAwCcAvVywcHD6mwKig/viewform?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/allbirds-ditches-sneakers-for-ai-compute?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Allbirds ditches sneakers for AI compute</a></p><p>Read our last Tech newsletter: <a href="https://tech.therundown.ai/p/meta-closing-in-on-google-ad-crown?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Meta closing in on Google ad crown</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/uber-10b-robotaxi-pivot?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Uber’s $10B robotaxi pivot</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/run-an-llm-on-your-laptop-for-free-with-ollama?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-s-superapp-hiding-inside-codex" target="_blank" rel="noreferrer">Run an LLM on your laptop for free with Ollama</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',101)])])}const w=a(i,[["render",o]]);export{h as __pageData,w as default};
